/**
 * MedX live accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Aria-live regions for toast and alert updates.
 */
const LIVE_TOKENS = Object.freeze({
  primary: { value: "a11y-live-primary", scope: "a11y" },
  secondary: { value: "a11y-live-secondary", scope: "a11y" },
  muted: { value: "a11y-live-muted", scope: "a11y" },
  accent: { value: "a11y-live-accent", scope: "a11y" },
  surface: { value: "a11y-live-surface", scope: "a11y" },
});

const LIVE_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const LIVE_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const liveRegistry = new Map();
const LIVE_listeners = new Set();
let LIVE_seq = 0;

function createLiveId(prefix = "medx-a11y-live") {
  LIVE_seq += 1;
  return `${prefix}-${LIVE_seq}`;
}

function registerLive(config = {}) {
  const entryId = config.id ?? createLiveId();
  const preset = LIVE_PRESETS[config.preset ?? "default"] ?? LIVE_PRESETS.default;
  const token = LIVE_TOKENS[config.token ?? preset.token] ?? LIVE_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: LIVE_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  liveRegistry.set(entryId, entry);
  notifyLiveListeners("register", entry);
  return entry;
}

function updateLive(id, patch = {}) {
  const entry = liveRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyLiveListeners("update", entry);
  return entry;
}

function resolveLive(id) {
  const entry = liveRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listLiveEntries(filter = {}) {
  let items = Array.from(liveRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onLiveEvent(listener) {
  LIVE_listeners.add(listener);
  return () => LIVE_listeners.delete(listener);
}

function notifyLiveListeners(type, entry) {
  for (const listener of LIVE_listeners) {
    try {
      listener({ type, entry, registrySize: liveRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:live] listener error", err.message);
    }
  }
}

function getLiveMetrics() {
  const items = listLiveEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(LIVE_TOKENS).length,
    presets: Object.keys(LIVE_PRESETS).length,
  };
}

async function runMedxLive() {
  console.log("[medx:ui:a11y:live] runtime initialized");
  console.log(`[medx:ui:a11y:live] tokens=${Object.keys(LIVE_TOKENS).length} presets=${Object.keys(LIVE_PRESETS).length}`);

  const events = [];
  onLiveEvent((e) => events.push(e.type));

  const domains = Object.keys(LIVE_SUPPLY_CHAIN);
  const presets = Object.keys(LIVE_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerLive({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/live" },
    });
  }

  const first = listLiveEntries()[0];
  if (first) updateLive(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getLiveMetrics();
  const resolved = first ? resolveLive(first.id) : null;

  console.log(`[medx:ui:a11y:live] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:live] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:live] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:live] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:live] bootstrap complete");
}

module.exports = runMedxLive;
